pub fn find(module: []const u8, name: []const u8) ?OpRecord {
    for (records) |r| if (std.mem.eql(u8, r.module, module) and std.mem.eql(u8, r.name, name)) return r;
    return null;
}
pub fn countKind(kind: ArchKind) usize {
    var n: usize = 0;
    for (records) |r| {
        if (r.kind == kind) n += 1;
    }
    return n;
}
pub fn countWithRules() usize {
    var n: usize = 0;
    for (records) |r| {
        if (r.rule_len != 0) n += 1;
    }
    return n;
}
pub fn countWithMlirTypeFactory() usize {
    var n: usize = 0;
    for (records) |r| {
        if (r.mlir_type_factory.len != 0) n += 1;
    }
    return n;
}
pub const ValidationInput = struct { module: []const u8, name: []const u8, arch: arch_catalog.SmArch = .sm90, a_dtype: typing.Numeric = typing.Float16, b_dtype: typing.Numeric = typing.Float16, acc_dtype: typing.Numeric = typing.Float32, shape_mnk: layout.Tree = layout.Tree.fromComptime(.{ 16, 8, 16 }) };
pub const Error = error{ UnknownArchOperation, UnsupportedArchitecture, UnsupportedOperandType, UnsupportedInstructionShape };
pub fn validateSourceBacked(input: ValidationInput) Error!void {
    const rec = find(input.module, input.name) orelse return Error.UnknownArchOperation;
    if (rec.kind == .copy or rec.kind == .mma) {
        if (rec.spec()) |s| {
            if (!s.supportsArch(input.arch)) return Error.UnsupportedArchitecture;
            if (rec.kind == .mma) {
                _ = s.makeMmaAtom(input.arch, input.a_dtype, input.b_dtype, input.acc_dtype, input.shape_mnk) catch |e| switch (e) {
                    error.UnsupportedOperandType => return Error.UnsupportedOperandType,
                    error.UnsupportedInstructionShape => return Error.UnsupportedInstructionShape,
                    error.UnsupportedArchitecture => return Error.UnsupportedArchitecture,
                    else => {},
                };
            }
        }
    }
}
test "arch exact manifest covers nvgpu and arch API records" {
    try std.testing.expect(records.len == source_arch_record_count);
    try std.testing.expect(source_arch_record_count >= 370);
    try std.testing.expect(countKind(.copy) >= 40);
    try std.testing.expect(countKind(.mma) >= 30);
    try std.testing.expect(countWithRules() >= 20);
    try std.testing.expect(find("nvgpu.warp.mma", "MmaF16BF16Op") != null);
    try std.testing.expect(find("nvgpu.tcgen05.mma", "MmaMXF4Op") != null);
}
test "arch exact validates source-backed known ops" {
    try validateSourceBacked(.{ .module = "nvgpu.warp.mma", .name = "MmaF16BF16Op", .arch = .sm80, .a_dtype = typing.Float16, .b_dtype = typing.Float16, .acc_dtype = typing.Float32, .shape_mnk = layout.Tree.fromComptime(.{ 16, 8, 16 }) });
    try std.testing.expectError(Error.UnknownArchOperation, validateSourceBacked(.{ .module = "nvgpu.warp.mma", .name = "DoesNotExist" }));
}
